import { ImageConfig } from '../types';

export const readFileAsDataURL = (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = () => resolve(reader.result as string);
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
};

export const processImage = async (
  sourceUrl: string,
  config: ImageConfig
): Promise<{ url: string; sizeKB: number }> => {
  return new Promise((resolve, reject) => {
    const img = new Image();
    img.onload = () => {
      const canvas = document.createElement('canvas');
      const ctx = canvas.getContext('2d');
      if (!ctx) {
        reject(new Error('Could not get canvas context'));
        return;
      }

      // 1. Calculate Crop (if AutoCrop is on)
      let sx = 0, sy = 0, sWidth = img.width, sHeight = img.height;

      if (config.autoCrop) {
        const targetRatio = config.width / config.height;
        const sourceRatio = img.width / img.height;

        if (sourceRatio > targetRatio) {
          // Source is wider than target: Crop width
          sWidth = img.height * targetRatio;
          sx = (img.width - sWidth) / 2;
        } else {
          // Source is taller than target: Crop height
          sHeight = img.width / targetRatio;
          sy = (img.height - sHeight) / 2;
        }
      }

      // 2. Resize
      canvas.width = config.width;
      canvas.height = config.height;

      // Draw background (white) for transparency handling
      ctx.fillStyle = '#FFFFFF';
      ctx.fillRect(0, 0, canvas.width, canvas.height);

      ctx.drawImage(img, sx, sy, sWidth, sHeight, 0, 0, config.width, config.height);

      // 3. Grayscale (if enabled)
      if (config.grayscale) {
        const imageData = ctx.getImageData(0, 0, canvas.width, canvas.height);
        const data = imageData.data;
        for (let i = 0; i < data.length; i += 4) {
          const avg = (data[i] + data[i + 1] + data[i + 2]) / 3;
          data[i] = avg;     // Red
          data[i + 1] = avg; // Green
          data[i + 2] = avg; // Blue
        }
        ctx.putImageData(imageData, 0, 0);
      }

      // 4. Compress to target KB
      let quality = 0.95;
      let dataUrl = canvas.toDataURL('image/jpeg', quality);

      // Binary search-ish approach for size
      // Fast iteration to find quality
      const maxBytes = config.maxKB * 1024;

      const calculateBytes = (dUrl: string) => Math.round((dUrl.length * 3) / 4);

      let attempts = 0;
      while (calculateBytes(dataUrl) > maxBytes && quality > 0.05 && attempts < 20) {
         // Decrease quality
         quality -= 0.05;
         dataUrl = canvas.toDataURL('image/jpeg', quality);
         attempts++;
      }

      resolve({
        url: dataUrl,
        sizeKB: calculateBytes(dataUrl) / 1024
      });
    };
    img.onerror = (err) => reject(err);
    img.src = sourceUrl;
  });
};

export const formatFileSize = (kb: number) => {
  if (kb < 1000) return `${kb.toFixed(1)} KB`;
  return `${(kb / 1024).toFixed(2)} MB`;
};

