import React from 'react';
import { EXAM_PRESETS } from '../constants';
import { ExamRequirement } from '../types';
import { ChevronDown } from 'lucide-react';

interface ExamDropdownProps {
  selectedExam: ExamRequirement;
  onSelect: (exam: ExamRequirement) => void;
  label: string;
}

const ExamDropdown: React.FC<ExamDropdownProps> = ({ selectedExam, onSelect, label }) => {
  const categories = Array.from(new Set(EXAM_PRESETS.map(e => e.category)));

  return (
    <div className="w-full mb-6 relative group">
      <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">
        {label}
      </label>
      <div className="relative">
        <select
          className="appearance-none block w-full px-4 py-3 text-base border-gray-300 dark:border-gray-600 focus:outline-none focus:ring-govBlue focus:border-govBlue sm:text-sm rounded-md shadow-sm bg-white dark:bg-gray-800 text-gray-900 dark:text-gray-100 pr-10"
          value={selectedExam.id}
          onChange={(e) => {
            const exam = EXAM_PRESETS.find(ex => ex.id === e.target.value);
            if (exam) onSelect(exam);
          }}
        >
          {categories.map((cat) => (
            <optgroup key={cat} label={cat} className="font-bold text-govBlue dark:text-blue-400">
              {EXAM_PRESETS.filter(e => e.category === cat).map(exam => (
                <option key={exam.id} value={exam.id} className="text-gray-900 dark:text-gray-100 font-normal">
                  {exam.name}
                </option>
              ))}
            </optgroup>
          ))}
        </select>
        <div className="pointer-events-none absolute inset-y-0 right-0 flex items-center px-2 text-gray-700 dark:text-gray-300">
          <ChevronDown size={16} />
        </div>
      </div>
      <div className="mt-2 text-xs text-gray-500 dark:text-gray-400">
        Selected: <span className="font-semibold text-govBlue dark:text-blue-400">{selectedExam.name}</span>
      </div>
    </div>
  );
};

export default ExamDropdown;

import React from 'react';
import { Upload, X, CheckCircle } from 'lucide-react';

interface ImageUploaderProps {
  title: string;
  image: string | null;
  onUpload: (file: File) => void;
  onClear: () => void;
  label: string;
  accept?: string;
}

const ImageUploader: React.FC<ImageUploaderProps> = ({
  title,
  image,
  onUpload,
  onClear,
  label,
  accept = "image/*"
}) => {
  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      onUpload(e.target.files[0]);
    }
  };

  return (
    <div className="flex flex-col w-full">
      <h3 className="text-md font-semibold text-gray-800 dark:text-gray-200 mb-2">{title}</h3>
      {!image ? (
        <label className="flex flex-col items-center justify-center w-full h-48 border-2 border-gray-300 border-dashed rounded-lg cursor-pointer bg-gray-50 dark:hover:bg-gray-800 dark:bg-gray-700 hover:bg-gray-100 dark:border-gray-600 dark:hover:border-gray-500 transition-all">
          <div className="flex flex-col items-center justify-center pt-5 pb-6">
            <Upload className="w-8 h-8 mb-3 text-gray-500 dark:text-gray-400" />
            <p className="mb-2 text-sm text-gray-500 dark:text-gray-400">
              <span className="font-semibold">Click to upload</span> or drag and drop
            </p>
            <p className="text-xs text-gray-500 dark:text-gray-400">{label}</p>
          </div>
          <input 
            type="file" 
            className="hidden" 
            accept={accept}
            onChange={handleChange}
          />
        </label>
      ) : (
        <div className="relative w-full h-48 bg-gray-100 dark:bg-gray-800 rounded-lg flex items-center justify-center overflow-hidden border border-gray-300 dark:border-gray-600">
           {/* eslint-disable-next-line @next/next/no-img-element */}
          <img src={image} alt="Preview" className="max-h-full max-w-full object-contain" />
          <button
            onClick={onClear}
            className="absolute top-2 right-2 bg-red-500 hover:bg-red-600 text-white p-1 rounded-full shadow-md transition-colors"
          >
            <X size={16} />
          </button>
          <div className="absolute bottom-2 left-2 bg-green-500 text-white text-xs px-2 py-1 rounded-full flex items-center gap-1 shadow-sm">
            <CheckCircle size={10} /> Loaded
          </div>
        </div>
      )}
    </div>
  );
};

export default ImageUploader;

import React from 'react';
import { Download, AlertTriangle, FileCheck } from 'lucide-react';
import { formatFileSize } from '../utils/imageProcessing';

interface ResultCardProps {
  processedUrl: string | null;
  fileSizeKB: number;
  width: number;
  height: number;
  reqMin: number;
  reqMax: number;
  onDownload: () => void;
  fileName: string;
  type: string;
}

const ResultCard: React.FC<ResultCardProps> = ({
  processedUrl,
  fileSizeKB,
  width,
  height,
  reqMin,
  reqMax,
  onDownload,
  fileName,
  type
}) => {
  if (!processedUrl) return null;

  const isSizeValid = fileSizeKB >= reqMin && fileSizeKB <= reqMax;

  return (
    <div className="mt-4 p-4 bg-white dark:bg-gray-800 rounded-lg shadow border border-gray-200 dark:border-gray-700">
      <div className="flex justify-between items-start mb-2">
        <div>
          <h4 className="font-semibold text-gray-900 dark:text-white">{type} Result</h4>
          <p className="text-sm text-gray-500 dark:text-gray-400">
            {width}x{height}px | {formatFileSize(fileSizeKB)}
          </p>
        </div>
        <div>
            {isSizeValid ? (
                <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-green-100 text-green-800 dark:bg-green-900 dark:text-green-200">
                    <FileCheck size={12} className="mr-1" /> Perfect
                </span>
            ) : (
                <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-yellow-100 text-yellow-800 dark:bg-yellow-900 dark:text-yellow-200">
                    <AlertTriangle size={12} className="mr-1" /> Check Size
                </span>
            )}
        </div>
      </div>

      {!isSizeValid && (
        <div className="mb-3 text-xs text-red-500 dark:text-red-400">
          Target: {reqMin}-{reqMax} KB. Current: {fileSizeKB.toFixed(1)} KB.
          <br/> Try uploading a smaller original or adjusting crop.
        </div>
      )}

      <button
        onClick={onDownload}
        className="w-full flex items-center justify-center gap-2 bg-govBlue hover:bg-blue-800 text-white font-medium py-2 px-4 rounded transition-colors"
      >
        <Download size={16} /> Download {fileName}
      </button>
    </div>
  );
};

export default ResultCard;

