  const [activeTab, setActiveTab] = useState<'home' | 'faq' | 'blog'>('home');
  const [menuOpen, setMenuOpen] = useState(false);

  // Exam State
  const [selectedExam, setSelectedExam] = useState<ExamRequirement>(EXAM_PRESETS[0]);

  // Image State
  const [photoOriginal, setPhotoOriginal] = useState<string | null>(null);
  const [photoProcessed, setPhotoProcessed] = useState<ProcessedImage | null>(null);

  const [signOriginal, setSignOriginal] = useState<string | null>(null);
  const [signProcessed, setSignProcessed] = useState<ProcessedImage | null>(null);

  const [isProcessing, setIsProcessing] = useState(false);

  // Theme Effect
  useEffect(() => {
    if (darkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [darkMode]);

  // Handlers
  const handlePhotoUpload = async (file: File) => {
    const url = await readFileAsDataURL(file);
    setPhotoOriginal(url);
    setPhotoProcessed(null); // Reset prev result
  };

  const handleSignUpload = async (file: File) => {
    const url = await readFileAsDataURL(file);
    setSignOriginal(url);
    setSignProcessed(null);
  };

  const processImages = async () => {
    setIsProcessing(true);
    try {
      if (photoOriginal) {
        const res = await processImage(photoOriginal, {
          width: selectedExam.photo.width,
          height: selectedExam.photo.height,
          maxKB: selectedExam.photo.maxKB,
          grayscale: false,
          resizeMode: selectedExam.photo.resizeMode
        });
        setPhotoProcessed({
          originalUrl: photoOriginal,
          processedUrl: res.url,
          fileSizeKB: res.sizeKB,
          width: selectedExam.photo.width,
          height: selectedExam.photo.height,
          name: `photo_${selectedExam.id}.jpg`
        });
      }

      if (signOriginal) {
        const res = await processImage(signOriginal, {
          width: selectedExam.signature.width,
          height: selectedExam.signature.height,
          maxKB: selectedExam.signature.maxKB,
          grayscale: true, // Auto convert signature to grayscale for better contrast
          resizeMode: selectedExam.signature.resizeMode
        });
        setSignProcessed({
          originalUrl: signOriginal,
          processedUrl: res.url,
          fileSizeKB: res.sizeKB,
          width: selectedExam.signature.width,
          height: selectedExam.signature.height,
          name: `sign_${selectedExam.id}.jpg`
        });
      }
    } catch (error) {
      console.error("Processing failed", error);
      alert(TRANSLATIONS[lang].error_compression);
    } finally {
      setIsProcessing(false);
    }
  };

  const downloadImage = (dataUrl: string, filename: string) => {
    const link = document.createElement('a');
    link.href = dataUrl;
    link.download = filename;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const t = TRANSLATIONS[lang];

  return (
    <div className="min-h-screen flex flex-col font-sans">
      {/* Navbar */}
      <nav className="bg-govBlue text-white shadow-lg sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex items-center justify-between h-16">
            <div className="flex items-center gap-2 cursor-pointer" onClick={() => setActiveTab('home')}>
               <div className="w-9 h-9 bg-white rounded-full flex items-center justify-center border-2 border-govSaffron shadow-sm text-govBlue">
                 <Camera size={20} />
               </div>
               <span className="font-bold text-xl tracking-tight hidden sm:block">{t.title}</span>
               <span className="font-bold text-lg tracking-tight sm:hidden">ExamResizer</span>
            </div>

            <div className="hidden md:block">
              <div className="ml-10 flex items-baseline space-x-4">
                <button onClick={() => setActiveTab('home')} className={`px-3 py-2 rounded-md text-sm font-medium ${activeTab === 'home' ? 'bg-blue-800' : 'hover:bg-blue-700'}`}>{t.home}</button>
                <button onClick={() => setActiveTab('blog')} className={`px-3 py-2 rounded-md text-sm font-medium ${activeTab === 'blog' ? 'bg-blue-800' : 'hover:bg-blue-700'}`}>{t.blog}</button>
                <button onClick={() => setActiveTab('faq')} className={`px-3 py-2 rounded-md text-sm font-medium ${activeTab === 'faq' ? 'bg-blue-800' : 'hover:bg-blue-700'}`}>{t.faq}</button>
              </div>
            </div>

            <div className="hidden md:flex items-center gap-4">
               <button onClick={() => setLang(l => l === 'en' ? 'hi' : 'en')} className="flex items-center gap-1 hover:text-gray-200">
                 <Languages size={18} /> {lang === 'en' ? 'Hindi' : 'English'}
               </button>
               <button onClick={() => setDarkMode(!darkMode)} className="hover:text-yellow-300">
                 {darkMode ? <Sun size={20} /> : <Moon size={20} />}
               </button>
            </div>

            <div className="-mr-2 flex md:hidden">
              <button onClick={() => setMenuOpen(!menuOpen)} className="inline-flex items-center justify-center p-2 rounded-md text-gray-200 hover:text-white hover:bg-blue-700 focus:outline-none">
                {menuOpen ? <X size={24} /> : <Menu size={24} />}
              </button>
            </div>
          </div>
        </div>

        {/* Mobile Menu */}
        {menuOpen && (
          <div className="md:hidden bg-blue-800 pb-4">
            <div className="px-2 pt-2 pb-3 space-y-1 sm:px-3">
              <button onClick={() => { setActiveTab('home'); setMenuOpen(false); }} className="block px-3 py-2 rounded-md text-base font-medium text-white hover:bg-blue-700 w-full text-left flex gap-2"><Home size={18}/> {t.home}</button>
              <button onClick={() => { setActiveTab('blog'); setMenuOpen(false); }} className="block px-3 py-2 rounded-md text-base font-medium text-white hover:bg-blue-700 w-full text-left flex gap-2"><FileText size={18}/> {t.blog}</button>
              <button onClick={() => { setActiveTab('faq'); setMenuOpen(false); }} className="block px-3 py-2 rounded-md text-base font-medium text-white hover:bg-blue-700 w-full text-left flex gap-2"><Info size={18}/> {t.faq}</button>
            </div>
            <div className="pt-4 pb-3 border-t border-blue-700 flex justify-around">
               <button onClick={() => setLang(l => l === 'en' ? 'hi' : 'en')} className="flex items-center gap-2 text-white">
                 <Languages size={18} /> {lang === 'en' ? 'Hi' : 'En'}
               </button>
               <button onClick={() => setDarkMode(!darkMode)} className="text-white">
                 {darkMode ? <Sun size={20} /> : <Moon size={20} />}
               </button>
            </div>
          </div>
        )}
      </nav>

      {/* Main Content Area */}
      <main className="flex-grow">
        {activeTab === 'home' && (
          <div className="max-w-7xl mx-auto px-4 py-8 sm:px-6 lg:px-8">

            <div className="text-center mb-10">
              <h1 className="text-3xl md:text-4xl font-extrabold text-gray-900 dark:text-white mb-2">
                {t.title}
              </h1>
              <p className="text-lg text-gray-600 dark:text-gray-300">
                {t.subtitle}
              </p>
            </div>

            <AdPlaceholder text={t.ad_placeholder} />

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
              {/* Left Column: Controls */}
              <div className="lg:col-span-1 space-y-6">
                <div className="bg-white dark:bg-gray-800 p-6 rounded-lg shadow-md border-t-4 border-govBlue">
                  <ExamDropdown 
                    selectedExam={selectedExam} 
                    onSelect={setSelectedExam} 
                    label={t.selectExam}
                  />

                  <div className="mt-4 p-4 bg-blue-50 dark:bg-blue-900/30 rounded border border-blue-100 dark:border-blue-800">
                    <h4 className="text-sm font-bold text-govBlue dark:text-blue-300 uppercase tracking-wide mb-2">{t.photoParams}</h4>
                    <div className="grid grid-cols-2 gap-2 text-sm text-gray-600 dark:text-gray-300">
                      <div>{t.width}: {selectedExam.photo.width}px</div>
                      <div>{t.height}: {selectedExam.photo.height}px</div>
                      <div>Min: {selectedExam.photo.minKB}KB</div>
                      <div>Max: {selectedExam.photo.maxKB}KB</div>
                      <div className="col-span-2 text-xs text-gray-500 mt-1 capitalize">Mode: {selectedExam.photo.resizeMode}</div>
                    </div>
                  </div>

                  <div className="mt-4 p-4 bg-orange-50 dark:bg-orange-900/20 rounded border border-orange-100 dark:border-orange-800">
                    <h4 className="text-sm font-bold text-govSaffron dark:text-orange-400 uppercase tracking-wide mb-2">{t.signParams}</h4>
                    <div className="grid grid-cols-2 gap-2 text-sm text-gray-600 dark:text-gray-300">
                      <div>{t.width}: {selectedExam.signature.width}px</div>
                      <div>{t.height}: {selectedExam.signature.height}px</div>
                      <div>Min: {selectedExam.signature.minKB}KB</div>
                      <div>Max: {selectedExam.signature.maxKB}KB</div>
                      <div className="col-span-2 text-xs text-gray-500 mt-1 capitalize">Mode: {selectedExam.signature.resizeMode}</div>
                    </div>
                  </div>
                </div>
              </div>

              {/* Right Column: Uploaders */}
              <div className="lg:col-span-2 space-y-8">

                {/* Photo Section */}
                <div className="bg-white dark:bg-gray-800 p-6 rounded-lg shadow-md">
                   <div className="grid md:grid-cols-2 gap-6">
                      <ImageUploader 
                        title={t.uploadPhoto}
                        image={photoOriginal} 
                        onUpload={handlePhotoUpload} 
                        onClear={() => { setPhotoOriginal(null); setPhotoProcessed(null); }}
                        label={t.dragDrop}
                      />
                      <div className="flex flex-col justify-end">
                         {photoProcessed ? (
                            <ResultCard 
                              processedUrl={photoProcessed.processedUrl}
                              fileSizeKB={photoProcessed.fileSizeKB}
                              width={photoProcessed.width}
                              height={photoProcessed.height}
                              reqMin={selectedExam.photo.minKB}
                              reqMax={selectedExam.photo.maxKB}
                              fileName={photoProcessed.name}
                              onDownload={() => downloadImage(photoProcessed.processedUrl!, photoProcessed.name)}
                              type={t.photoParams.split(' ')[0]}
                            />
                         ) : (
                           <div className="h-full flex items-center justify-center text-gray-400 text-sm italic border rounded-lg bg-gray-50 dark:bg-gray-700/50 p-4">
                             {t.result} {t.preview}
                           </div>
                         )}
                      </div>
                   </div>
                </div>

                {/* Signature Section */}
                <div className="bg-white dark:bg-gray-800 p-6 rounded-lg shadow-md">
                   <div className="grid md:grid-cols-2 gap-6">
                      <ImageUploader 
                        title={t.uploadSign}
                        image={signOriginal} 
                        onUpload={handleSignUpload} 
                        onClear={() => { setSignOriginal(null); setSignProcessed(null); }}
                        label={t.dragDrop}
                      />
                       <div className="flex flex-col justify-end">
                         {signProcessed ? (
                            <ResultCard 
                              processedUrl={signProcessed.processedUrl}
                              fileSizeKB={signProcessed.fileSizeKB}
                              width={signProcessed.width}
                              height={signProcessed.height}
                              reqMin={selectedExam.signature.minKB}
                              reqMax={selectedExam.signature.maxKB}
                              fileName={signProcessed.name}
                              onDownload={() => downloadImage(signProcessed.processedUrl!, signProcessed.name)}
                              type={t.signParams.split(' ')[0]}
                            />
                         ) : (
                           <div className="h-full flex items-center justify-center text-gray-400 text-sm italic border rounded-lg bg-gray-50 dark:bg-gray-700/50 p-4">
                             {t.result} {t.preview}
                           </div>
                         )}
                      </div>
                   </div>
                </div>

                {/* Global Action */}
                <div className="flex justify-center pt-4">
                  <button 
                    onClick={processImages}
                    disabled={(!photoOriginal && !signOriginal) || isProcessing}
                    className={`
                      w-full md:w-auto px-10 py-4 rounded-lg font-bold text-lg shadow-lg transition-all
                      ${(!photoOriginal && !signOriginal) || isProcessing
                        ? 'bg-gray-300 text-gray-500 cursor-not-allowed dark:bg-gray-700'
                        : 'bg-gradient-to-r from-govSaffron to-orange-600 text-white hover:shadow-xl hover:scale-105 active:scale-95'
                      }
                    `}
                  >
                    {isProcessing ? t.processing : t.compress}
                  </button>
                </div>

                <AdPlaceholder text={t.ad_placeholder} />

              </div>
            </div>
          </div>
        )}

        {activeTab === 'faq' && <FAQSection lang={lang} />}
        {activeTab === 'blog' && <BlogSection lang={lang} />}

      </main>

      {/* Footer */}
      <footer className="bg-gray-800 text-gray-300 py-8 mt-12">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
           <div className="grid md:grid-cols-3 gap-8 mb-8">
              <div>
                <h3 className="text-white font-bold mb-4">{t.title}</h3>
                <p className="text-sm">
                  Made with ❤️ for Indian Students. Simplify your exam application process with our privacy-focused tools.
                </p>
              </div>
              <div>
                <h3 className="text-white font-bold mb-4">Quick Links</h3>
                <ul className="space-y-2 text-sm">
                   <li><button onClick={() => setActiveTab('home')} className="hover:text-white">Home</button></li>
                   <li><button onClick={() => setActiveTab('blog')} className="hover:text-white">Exam Guidelines</button></li>
                   <li><button onClick={() => setActiveTab('faq')} className="hover:text-white">Help & FAQ</button></li>
                </ul>
              </div>
              <div>
                <h3 className="text-white font-bold mb-4">Legal</h3>
                <p className="text-xs text-gray-400 mb-2">
                  {t.disclaimer}
                </p>
                <p className="text-xs text-gray-500">
                  &copy; {new Date().getFullYear()} ExamResizer Pro. All rights reserved.
                </p>
              </div>
           </div>
        </div>
      </footer>
    </div>
  );
}

